// Prepara parametri con valori di default
const input = $input.all()[0].json;

return [{
  json: {
    repo: input.repo || input.repository,
    state: input.state || "open",
    labels: input.labels || "",
    assignee: input.assignee || "",
    sort: input.sort || "created",
    per_page: parseInt(input.per_page || "100")
  }
}];

// Gestione corretta per n8n
const items = $input.all();

if (!items || items.length === 0) {
  return [{ 
    json: { 
      issues: [], 
      count: 0,
      message: "No data received"
    } 
  }];
}

// In n8n, quando HTTP Request restituisce un array,
// ogni elemento dell'array diventa un item separato
let issues = [];

// Caso 1: Ogni item è una singola issue
if (items.length > 1) {
  // items = [{json: issue1}, {json: issue2}, ...]
  issues = items
    .map(item => item.json)
    .filter(issue => issue && !issue.pull_request);
}
// Caso 2: Un solo item che contiene l'array
else if (items.length === 1) {
  const data = items[0].json;

  // Se è già un array
  if (Array.isArray(data)) {
    issues = data.filter(issue => !issue.pull_request);
  }
  // Se l'array è in una proprietà
  else if (data.items && Array.isArray(data.items)) {
    issues = data.items.filter(issue => !issue.pull_request);
  }
  // Se è un singolo oggetto issue
  else if (data && data.number && data.title) {
    issues = [data];
  }
}

if (issues.length === 0) {
  return [{ 
    json: { 
      issues: [], 
      count: 0,
      message: "No issues found"
    } 
  }];
}

// Formatta ogni issue
const formatted = issues.map(issue => ({
  number: issue.number,
  title: issue.title,
  state: issue.state,
  body: issue.body || "",
  url: issue.html_url,
  created_at: issue.created_at,
  updated_at: issue.updated_at,
  closed_at: issue.closed_at || null,
  labels: (issue.labels || []).map(l => l.name),
  assignees: (issue.assignees || []).map(a => a.login),
  user: issue.user ? issue.user.login : "unknown",
  comments: issue.comments || 0
}));

return [{ 
  json: { 
    issues: formatted,
    count: formatted.length,
    message: `Found ${formatted.length} issue(s)`
  } 
}];

// Costruisci URL per GitHub API
const params = $input.all()[0].json;

// URL base
let url = `https://api.github.com/repos/${params.repo}/issues`;

// Array di parametri query
const queryParams = [
  `state=${params.state}`,
  `per_page=${params.per_page}`,
  `sort=${params.sort}`
];

// Aggiungi labels solo se presente
if (params.labels && params.labels.trim().length > 0) {
  queryParams.push(`labels=${params.labels}`);
}

// Aggiungi assignee solo se presente
if (params.assignee && params.assignee.trim().length > 0) {
  queryParams.push(`assignee=${params.assignee}`);
}

// Unisci tutto
url = url + '?' + queryParams.join('&');

return [{
  json: {
    url: url
  }
}];
